type AuthError =
  | { type: 'InvalidCredentials'; message: string }
  | { type: 'UserNotFound'; message: string }
  | { type: 'NetworkError'; code: number; message: string };

function authenticate(username: string, password: string): AuthError | { userId: string } {
  if (username !== 'admin') {
    return { type: 'UserNotFound', message: 'No user with that name exists.' };
  }
  if (password !== '1234') {
    return { type: 'InvalidCredentials', message: 'Password is incorrect.' };
  }
  // Simulate success
  return { userId: 'abc123' };
}

const result = authenticate('admin', 'wrong');

if ('type' in result) {
  // TypeScript knows `result` is of type AuthError here
  switch (result.type) {
    case 'InvalidCredentials':
      console.error('Error:', result.message);
      break;
    case 'UserNotFound':
      console.error('Error:', result.message);
      break;
    case 'NetworkError':
      console.error(`Network error ${result.code}: ${result.message}`);
      break;
  }
} else {
  console.log('Authentication successful. User ID:', result.userId);
}

class VerboseMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"Creating class {name} with VerboseMeta")
        return super().__new__(cls, name, bases, dct)

class MyClass(metaclass=VerboseMeta):
    pass

# Output: Creating class MyClass with VerboseMeta

class InterfaceMeta(type):
    def __init__(cls, name, bases, dct):
        super().__init__(name, bases, dct)
        # Check if subclass defines a 'process' method
        if 'process' not in dct:
            raise TypeError(f"Class {name} must define a 'process' method.")

class Base(metaclass=InterfaceMeta):
    pass

# This will work
class Worker(Base):
    def process(self):
        print("Processing...")

# This will raise TypeError
